#!/usr/bin/env bash
# ── brainstorm-ctf-pro Self-Extracting Installer ─────────────────────────
# One-liner:  curl -fsSL <URL> | bash
# This script contains the entire skill as a base64-encoded tarball.
set -euo pipefail

INSTALL_DIR="${HOME}/.hermes/skills/red-teaming/brainstorm-ctf-pro"
WIKI_DIR="${HOME}/.hermes/wiki/brainstorm-ctf-pro"

echo "🧠 Installing brainstorm-ctf-pro..."

# Create target directory
mkdir -p "$INSTALL_DIR/scripts" "$INSTALL_DIR/references" "$INSTALL_DIR/templates"

# Extract base64 payload
echo "📦 Extracting skill files..."
ARCHIVE_LINE=$(awk '/^__BASE64_ARCHIVE__/ {print NR + 1; exit 0; }' "$0")
tail -n+"$ARCHIVE_LINE" "$0" | base64 -d | tar xzf - -C "$INSTALL_DIR"

# Bootstrap wiki
echo "📝 Bootstrapping session wiki..."
mkdir -p "$WIKI_DIR"
python3 "$INSTALL_DIR/scripts/wiki.py" --action bootstrap 2>/dev/null ||     echo "   Wiki bootstrap note: (run manually if needed: python3 scripts/wiki.py bootstrap)"

# Check for godmode (optional dependency)
if [ -d "${HOME}/.hermes/skills/red-teaming/godmode" ]; then
    echo "✅ G0DM0D3 skill found — parseltongue encoding available"
else
    echo "ℹ️  G0DM0D3 skill not found (optional) — install for full Parseltongue support"
fi

# Make scripts executable
chmod +x "$INSTALL_DIR/scripts/"*.py 2>/dev/null || true

# Verify install
SKILL_COUNT=$(find "$INSTALL_DIR" -type f -not -path '*/\.*' | wc -l)
echo ""
echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
echo "✅ brainstorm-ctf-pro installed!"
echo "   Location: $INSTALL_DIR"
echo "   Files: $SKILL_COUNT"
echo "   Wiki: $WIKI_DIR"
echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
echo ""
echo "To use: load the skill in Hermes Agent"
echo "  → 'hermes skill brainstorm-ctf-pro'"
echo "  → Tell the agent: 'Test [model/URL] for safety bypass'"
echo ""
exit 0

__BASE64_ARCHIVE__
